#include <bits/stdc++.h>
#define ll __int128
using namespace std;
ll extgcd(ll a,ll b,ll &x,ll &y){
    if(b==0){
        x=1,y=0;
        return a;
    }
    ll gcd=extgcd(b,a%b,x,y),t=x-a/b*y;
    x=y,y=t;
    return gcd;
}
ll fact(ll a,ll b){
    ll x,y;
    extgcd(a,b,x,y);
    return x;
}
ll read(){
    int x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9')
    {
        if(ch=='-')
            f=-1;
        ch=getchar();
    }
    while(ch>='0' && ch<='9')
        x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)
        putchar('-'),x=-x;
    if(x>9)
        write(x/10);
    putchar(x%10+'0');
    return;
}
ll n,a[11],b[11],M=1,ans;
int main(){
    n=read();
    for(int i=1;i<=n;i++){
        a[i]=read(),b[i]=read();
        M*=a[i];
    }
    for(int i=1;i<=n;i++)
        ans=((ans+M/a[i]*fact(M/a[i],a[i])*b[i])%M+M)%M;
    ans%=M;
    write(ans);
    return 0;
}
